object TenantContext {
    private const val TENANT_KEY = "tenantId"
    private const val DEFAULT_TENANT = "default"

    fun getCurrentTenant(): Mono<String> {
        return Mono.deferContextual { ctx ->
            Mono.just(ctx.getOrDefault(TENANT_KEY, DEFAULT_TENANT))
        }
    }

    fun getCurrentTenantOrEmpty(): Mono<String> {
        return Mono.deferContextual { ctx ->
            val tenantId = ctx.getOrEmpty<String>(TENANT_KEY)
            if (tenantId.isPresent) Mono.just(tenantId.get())
            else Mono.empty()
        }
    }

    fun withTenant(tenantId: String): Context {
        return Context.of(TENANT_KEY, tenantId)
    }

    fun contextModifier(tenantId: String): (Context) -> Context {
        return { it.put(TENANT_KEY, tenantId) }
    }
}
```

