1. Create `TenantConnectionRegistry.kt`:
```kotlin
@Component
class TenantConnectionRegistry(
    private val tenantRepository: TenantRepository,
    private val connectionFactoryOptions: ConnectionFactoryOptions
) {
    private val connectionFactories = ConcurrentHashMap<String, ConnectionFactory>()

    fun getConnectionFactory(tenantId: String): Mono<ConnectionFactory> {
        return Mono.justOrEmpty(connectionFactories[tenantId])
            .switchIfEmpty(
                tenantRepository.findById(UUID.fromString(tenantId))
                    .filter { it.status == TenantStatus.ACTIVE }
                    .map { tenant -> createConnectionFactory(tenant) }
                    .doOnNext { cf -> connectionFactories[tenantId] = cf }
            )
    }

    private fun createConnectionFactory(tenant: Tenant): ConnectionFactory {
        return ConnectionFactories.get(
            ConnectionFactoryOptions.builder()
                .option(DRIVER, "postgresql")
                .option(HOST, tenant.dbHost)
                .option(PORT, tenant.dbPort)
                .option(DATABASE, tenant.dbName)
                .option(USER, tenant.dbUsername)
                .option(PASSWORD, tenant.dbPassword)
                .build()
        )
    }

    fun invalidateCache(tenantId: String) {
        connectionFactories.remove(tenantId)
    }

    fun preloadTenants(): Mono<Void> {
        return tenantRepository.findByStatus(TenantStatus.ACTIVE)
            .flatMap { tenant -> getConnectionFactory(tenant.id.toString()) }
            .then()
    }
}
```

