class TenantRoutingConnectionFactory(
    private val tenantRegistry: TenantConnectionRegistry,
    private val defaultConnectionFactory: ConnectionFactory
) : AbstractRoutingConnectionFactory() {

    override fun determineCurrentLookupKey(): Mono<Any> {
        return TenantContext.getCurrentTenant()
            .cast(Any::class.java)
    }

    override fun determineTargetConnectionFactory(key: Any): Mono<ConnectionFactory> {
        val tenantId = key as String
        return if (tenantId == "default" || tenantId == "meta") {
            Mono.just(defaultConnectionFactory)
        } else {
            tenantRegistry.getConnectionFactory(tenantId)
                .switchIfEmpty(Mono.error(TenantNotFoundException("Tenant not found: $tenantId")))
        }
    }
}
