Create web filter in `adapter/inbound/web/filter/`:

1. Create `TenantWebFilter.kt`:
```kotlin
@Component
@Order(Ordered.HIGHEST_PRECEDENCE + 10)  // After security filter
class TenantWebFilter(
    private val jwtDecoder: ReactiveJwtDecoder,
    private val tenantRepository: TenantRepository
) : WebFilter {

    override fun filter(exchange: ServerWebExchange, chain: WebFilterChain): Mono<Void> {
        return extractTenantId(exchange)
            .flatMap { tenantId -> validateTenant(tenantId) }
            .flatMap { tenantId ->
                chain.filter(exchange)
                    .contextWrite(TenantContext.contextModifier(tenantId))
            }
            .switchIfEmpty(chain.filter(exchange))  // No tenant for public endpoints
    }

    private fun extractTenantId(exchange: ServerWebExchange): Mono<String> {
        // 1. Try X-Tenant-ID header first (for admin/internal calls)
        val headerTenant = exchange.request.headers.getFirst("X-Tenant-ID")
        if (!headerTenant.isNullOrBlank()) {
            return Mono.just(headerTenant)
        }

        // 2. Try JWT claim
        return extractFromJwt(exchange)
    }

    private fun extractFromJwt(exchange: ServerWebExchange): Mono<String> {
        val authHeader = exchange.request.headers.getFirst(HttpHeaders.AUTHORIZATION)
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            return Mono.empty()
        }
        val token = authHeader.substring(7)
        return jwtDecoder.decode(token)
            .mapNotNull { jwt -> jwt.getClaimAsString("tenantId") }
    }

    private fun validateTenant(tenantId: String): Mono<String> {
        return tenantRepository.findById(UUID.fromString(tenantId))
            .filter { it.status == TenantStatus.ACTIVE }
            .map { tenantId }
            .switchIfEmpty(Mono.error(TenantNotFoundException("Invalid or inactive tenant")))
    }
}
```

