```kotlin
// JwtTokenService.kt
@Service
class JwtTokenService(
    private val redisTemplate: ReactiveRedisTemplate<String, String>,
    @Value("\${jwt.secret}") private val secret: String,
    @Value("\${jwt.access-expiration}") private val accessExp: Long,
    @Value("\${jwt.refresh-expiration}") private val refreshExp: Long
) {
    fun generateTokenPair(user: User, tenantId: String): TokenPair {
        val accessToken = Jwts.builder()
            .subject(user.id.toString())
            .claim("role", user.role.name)
            .claim("tenantId", tenantId)
            .issuedAt(Date())
            .expiration(Date(System.currentTimeMillis() + accessExp))
            .signWith(Keys.hmacShaKeyFor(secret.toByteArray()))
            .compact()
        // Similar for refresh token
        return TokenPair(accessToken, refreshToken)
    }

    fun validateToken(token: String): Mono<Boolean> {
        return redisTemplate.hasKey("blacklist:$token")
            .map { blacklisted -> !blacklisted && parseToken(token) != null }
    }

    fun blacklistToken(token: String): Mono<Boolean> {
        val expiry = getRemainingExpiry(token)
        return redisTemplate.opsForValue()
            .set("blacklist:$token", "1", Duration.ofMillis(expiry))
    }
}

