class JwtTokenService(
    private val jwtProperties: JwtProperties
) {
    private val signingKey by lazy { Keys.hmacShaKeyFor(jwtProperties.secret.toByteArray()) }

    fun generateTokenPair(userId: UUID, role: String, tenantId: String): TokenPair {
