        - issuedAt: Date()
        - expiration: Date(System.currentTimeMillis() + expiration)
        - signWith(signingKey, Jwts.SIG.HS256)

    fun parseToken(token: String): JwtClaims? - Parse and validate token, return null if invalid/expired
