Create be/api/src/main/kotlin/com/counseling/api/infrastructure/redis/TokenBlacklistService.kt:

@Service
class TokenBlacklistService(
    private val redisTemplate: ReactiveRedisTemplate<String, String>,
    private val jwtTokenService: JwtTokenService
) {
    companion object {
        private const val BLACKLIST_PREFIX = "blacklist:"
    }

    fun blacklistToken(token: String): Mono<Boolean> {
        val expiry = jwtTokenService.getRemainingExpiry(token)
        if (expiry <= 0) return Mono.just(true) // Already expired
        return redisTemplate.opsForValue()
            .set("$BLACKLIST_PREFIX$token", "1", Duration.ofMillis(expiry))
    }

    fun isBlacklisted(token: String): Mono<Boolean> {
        return redisTemplate.hasKey("$BLACKLIST_PREFIX$token")
    }

    fun blacklistAllUserTokens(userId: UUID): Mono<Long> - For password change scenarios
}

