                channelRepository.save(channel)
                    .flatMap { savedChannel ->
                        liveKitService.createRoom(savedChannel.id.toString())
                            .flatMap { room ->
                                createEndpoints(savedChannel, agent, customerInfo)
                                    .map { (agentEndpoint, customerEndpoint) ->
                                        ChannelResponse(
