                                            livekitUrl = liveKitProperties.url,
                                            agentToken = liveKitService.generateAgentToken(room.name, agentId, agent.name),
                                            customerToken = liveKitService.generateCustomerToken(room.name, customerEndpoint.id.toString(), customerInfo.name)
                                        )
                                    }
                            }
                    }
            }
            .doOnSuccess { eventPublisher.publishEvent(ChannelCreatedEvent(it.channelId)) }
    }

    @Transactional
