@Service
class NotificationService(
    private val sinkMap: ConcurrentHashMap<String, Sinks.Many<NotificationEvent>>,
    private val emailService: EmailService
) {
    fun sendInAppNotification(userId: String, notification: NotificationEvent): Mono<Void> {
        return Mono.fromRunnable {
            sinkMap[userId]?.tryEmitNext(notification)
        }
    }

    fun subscribeToNotifications(userId: String): Flux<NotificationEvent> {
        val sink = Sinks.many().multicast().onBackpressureBuffer<NotificationEvent>()
        sinkMap[userId] = sink
        return sink.asFlux()
            .doOnCancel { sinkMap.remove(userId) }
    }

