    fun sendPasswordResetEmail(email: String, tempPassword: String): Mono<Void> {
        return emailService.send(EmailMessage(
            to = email,
            subject = "Password Reset",
            template = "password-reset",
            variables = mapOf("tempPassword" to tempPassword)
        ))
    }
