  const cobrowseTrack = screenShareTracks.find(t => t.name === 'cobrowse')

  const sendPointer = (e: MouseEvent) => {
    const rect = videoRef.current.getBoundingClientRect()
    room.localParticipant.publishData(
      JSON.stringify({
        type: 'pointer',
        x: (e.clientX - rect.left) / rect.width,
        y: (e.clientY - rect.top) / rect.height
      }),
      { reliable: false }
    )
  }

  return (
    <div onMouseMove={sendPointer}>
      <VideoTrack track={cobrowseTrack} />
      <OverlayToolbar onHighlight={sendHighlight} />
