Reconnection handling with LiveKit:

```typescript
// useReconnection.ts
export function useReconnection() {
  const room = useRoomContext()
  const [connectionState, setConnectionState] = useState<ConnectionState>('connected')
  const [reconnectAttempt, setReconnectAttempt] = useState(0)
  const MAX_RECONNECT_ATTEMPTS = 3

  useEffect(() => {
    const handleDisconnected = () => {
      setConnectionState('disconnected')
      setReconnectAttempt(0)
    }

    const handleReconnecting = () => {
      setConnectionState('reconnecting')
      setReconnectAttempt(prev => prev + 1)
    }

    const handleReconnected = () => {
      setConnectionState('connected')
      setReconnectAttempt(0)
    }

    room.on(RoomEvent.Disconnected, handleDisconnected)
    room.on(RoomEvent.Reconnecting, handleReconnecting)
    room.on(RoomEvent.Reconnected, handleReconnected)

    return () => {
      room.off(RoomEvent.Disconnected, handleDisconnected)
      room.off(RoomEvent.Reconnecting, handleReconnecting)
      room.off(RoomEvent.Reconnected, handleReconnected)
    }
  }, [room])

  return { connectionState, reconnectAttempt, maxAttempts: MAX_RECONNECT_ATTEMPTS }
}

// ConnectionStatus.tsx
export function ConnectionStatus() {
  const { connectionState, reconnectAttempt, maxAttempts } = useReconnection()

  if (connectionState === 'connected') return null

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 bg-amber-100 p-4 rounded-lg">
      {connectionState === 'reconnecting' && (
        <>
          <Spinner /> Reconnecting... ({reconnectAttempt}/{maxAttempts})
        </>
      )}
      {connectionState === 'disconnected' && (
        <>
          <AlertIcon /> Connection lost
          <Button onClick={() => room.connect()}>Retry</Button>
        </>
      )}
    </div>
  )
}
